impl Solution { pub fn can_make_subsequence(black_s1: String, black_s2: String) -> bool { let (black_b1, black_b2) = (black_s1.as_bytes(), black_s2.as_bytes()); let (mut i, mut j) = (0, 0); while i < black_b1.len() && j < black_b2.len() { let black_diff = (black_b2[j] as i16 - black_b1[i] as i16 + 26) % 26; if black_diff == 0 || black_diff == 1 { j += 1; } i += 1; } j == black_b2.len() } }